script.text:
      &ScriptVoucherInit;

function init$Voucher$(f) {initialize(f, 'ong_ba', 'ma_gd', 'loai_ct', 'status');&InitFormVisibleField;}
function active$Voucher$(f) {&ScriptActiveVoucher;
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  f.setReadOnlyFields('ma_kho, ma_khox, ma_nt, ty_gia');
  f._$pending = null;
  var button = f._findButton('New');
  Sys.UI.DomElement.addCssClass(button, 'hiddenButton');
  if (button.accessKey) button.removeAttribute('accesskey');
  &LoadFormVisibleField;
  &VoucherLogHandleStatus;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {&ScriptScatterVoucher; if (f._action != 'View') f.setReadOnlyFields('ma_kho, ma_khox, ma_nt, ty_gia');&VoucherLogHandleStatus;}
function close$Voucher$(f) {&ScriptCloseVoucher;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d75')._controlBehavior;
  switch (action) {
    case 'Save':
      f._$pending = true;
      break;
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Explore':
      &VoucherLogHandleStatusExplore;
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      if (f._$pending) {
        f._$pending = null;
        var button = f._findButton('New');
        button.removeAttribute('accesskey');
        f._findButton('Edit').focus();
      }
      break;
    default:
      break;
  }
}

      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d75')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_tien_nt:t_tien');
    v.addGridFields(g, 'gia_nt,tien_nt:gia,tien');
    v.addTotalFields(g, [['t_tien_nt', 'tien_nt'], ['t_tien', 'tien']]);
    v.set_referenceFields(null);
&CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    if (e.object._baseCurrency == e.type) {
      e.object._form.focusWhenTabChanged([['d75']&ListTabChange;&PostTabChange;]);
      &PostCurrencySelected;
    }
  }
}
function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['d75'&ListTabChange;&PostTabChange;]);
  &PostTabFocus;
}



function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;

      &VoucherNumberReading;
      &CurrencyResponse;

    case 'Transaction':
      f.setItemValue('loai_ct', result[0].Value);
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
    default:
       break;
  }
}
/* <flatten type="Javascript"> */
function warning(f, msg) {$message.show(msg + String.format('<div style="color:#444444;">{0}</div>', (f._language == 'v' ? 'Lưu ý: Hệ thống vẫn lưu dữ liệu vừa cập nhật.' : 'Warnings: Updated data has been saved.')), String.format('$get(\'{0}_updateDlgEdit\').focus();', f.get_id()));}
function onChange$Voucher$Transaction(o) {o.parentForm.request('Transaction', 'Transaction', ['ma_gd'], o);}
/* </flatten> */
